#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e6+5;
LL Q,n,a[N],h[N],A,B,Answer;
map<pair<LL,LL>,LL> mp;stack<LL> st;
mt19937 Rd(time(0));
LL min(LL x,LL y){return (x<y?x:y);}
LL max(LL x,LL y){return (x>y?x:y);}
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int main(){
    n=read(),A=0,B=0;
    for(int i=1;i<=n;i++){char ch;cin>>ch;a[i]=ch-'a'+1;}
    for(int i=1;i<=n;i++)h[i]=Rd();
    mp.clear();mp[{0,0}]++;Answer=0;
    for(int i=1;i<=n;i++){
        if(!st.empty()&&st.top()==a[i])
            A^=a[i]*h[st.size()],B+=a[i]^h[st.size()],st.pop();
        else st.push(a[i]),A^=a[i]*h[st.size()],B-=a[i]^h[st.size()];
        Answer+=mp[{A,B}],mp[{A,B}]++;
    }
    cout<<Answer<<"\n";
    return 0;
}
